import * as esbuild from 'esbuild';
import fs from 'node:fs';
import path from 'node:path';

const root = path.resolve(import.meta.dirname, '..');
const entry = path.join(root, 'scripts/gas-webpush-entry.js');
const outFile = path.join(root, 'apps-script/WebPush.generated.gs');

const result = await esbuild.build({
  entryPoints: [entry],
  bundle: true,
  format: 'iife',
  globalName: 'WebPushLib',
  platform: 'browser',
  target: ['es2017'],
  write: false,
  minify: true,
});

const bundled = result.outputFiles[0].text;
const gas = `/**
 * Generated by scripts/build-gas-webpush.mjs — do not edit by hand.
 */
${bundled}

function sendWebPush_(subscription, vapidPublicKey, vapidPrivateKey, payload, subject) {
  var request = WebPushLib.buildPushRequest(
    subscription,
    vapidPublicKey,
    vapidPrivateKey,
    payload || null,
    subject || 'mailto:planner@b4l.local',
  );
  var headers = {};
  Object.keys(request.headers).forEach(function(key) {
    headers[key] = request.headers[key];
  });
  return UrlFetchApp.fetch(request.endpoint, {
    method: 'post',
    headers: headers,
    payload: request.body,
    muteHttpExceptions: true,
  });
}
`;

fs.mkdirSync(path.dirname(outFile), { recursive: true });
fs.writeFileSync(outFile, gas);
console.log(`Wrote ${outFile}`);
